'use client'
import { cn } from '@cascivo/core'
import type { HTMLAttributes } from 'react'
import styles from './prose.module.css'

export type ProseProps = HTMLAttributes<HTMLDivElement>

export function Prose({ className, children, ...props }: ProseProps) {
  return (
    <div className={cn(styles['prose'], className as string | undefined)} {...props}>
      {children}
    </div>
  )
}

@layer cascivo.component {
  .prose {
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-base);
    line-height: var(--cascivo-leading-relaxed);
    color: var(--cascivo-color-text);

    & > * {
      margin-block: 0;
    }

    & > * + * {
      margin-block-start: var(--cascivo-space-4);
    }

    & h1,
    & h2,
    & h3,
    & h4,
    & h5,
    & h6 {
      font-weight: var(--cascivo-font-semibold);
      line-height: var(--cascivo-leading-tight);
      color: var(--cascivo-color-text);
      text-wrap: balance;
    }

    & h1 {
      font-size: var(--cascivo-text-3xl);
      letter-spacing: var(--cascivo-tracking-tight);
    }

    & h2 {
      font-size: var(--cascivo-text-2xl);
      letter-spacing: var(--cascivo-tracking-tight);
    }

    & h3 {
      font-size: var(--cascivo-text-xl);
    }

    & h4 {
      font-size: var(--cascivo-text-lg);
    }

    & h5,
    & h6 {
      font-size: var(--cascivo-text-base);
    }

    & > * + h2 {
      margin-block-start: var(--cascivo-space-8);
    }

    & > * + h3 {
      margin-block-start: var(--cascivo-space-6);
    }

    & ul,
    & ol {
      padding-inline-start: var(--cascivo-space-6);
    }

    & ul {
      list-style-type: disc;
    }

    & ol {
      list-style-type: decimal;
    }

    & li {
      margin-block: var(--cascivo-space-1);
    }

    & li > ul,
    & li > ol {
      margin-block-start: var(--cascivo-space-1);
    }

    & code {
      font-family: var(--cascivo-font-mono);
      font-size: 0.875em;
      background-color: var(--cascivo-color-surface);
      border: 1px solid var(--cascivo-color-border);
      border-radius: var(--cascivo-radius-indicator);
      padding-block: 0.0625rem;
      padding-inline: var(--cascivo-space-1);
    }

    & blockquote {
      border-inline-start: 3px solid var(--cascivo-color-border-strong);
      padding-inline-start: var(--cascivo-space-4);
      color: var(--cascivo-color-text-subtle);
    }

    & a {
      color: var(--cascivo-color-accent);
      text-decoration: underline;
      text-underline-offset: 0.15em;

      &:hover {
        color: var(--cascivo-color-accent-hover);
      }
    }

    & table {
      inline-size: 100%;
      border-collapse: collapse;
      font-size: var(--cascivo-text-sm);
    }

    & th,
    & td {
      border-block-end: 1px solid var(--cascivo-color-border);
      padding-block: var(--cascivo-space-2);
      padding-inline: var(--cascivo-space-3);
      text-align: start;
    }

    & th {
      font-weight: var(--cascivo-font-semibold);
    }

    & img {
      max-inline-size: 100%;
      block-size: auto;
      border-radius: var(--cascivo-radius-surface);
    }

    & hr {
      border: none;
      border-block-start: 1px solid var(--cascivo-color-border);
    }
  }
}
